import java.io.FileInputStream;
import java.io.IOException;
import java.io.ObjectInputFilter;
import java.io.ObjectInputStream;

public class DeserializationUtil {

    /**
     * Reads a serialized object from the specified file.
     * Applies a restrictive ObjectInputFilter to mitigate insecure deserialization risks.
     *
     * @param filePath the path to the file containing the serialized object
     * @return the deserialized object
     * @throws RuntimeException if reading fails or the object is not allowed by the filter
     */
    public static Object readObjectFromFile(String filePath) {
        try (FileInputStream fis = new FileInputStream(filePath);
             ObjectInputStream ois = new ObjectInputStream(fis)) {

            // Restrictive filter: allow only classes from java.base module; deny all others.
            ObjectInputFilter filter = ObjectInputFilter.Config.createFilter("java.base/*;!*");
            ois.setObjectInputFilter(filter);

            return ois.readObject();
        } catch (IOException | ClassNotFoundException e) {
            // Wrap in an unchecked exception to avoid leaking internal details.
            throw new RuntimeException("Failed to read object from file", e);
        }
    }
}
