using System;
using System.Data;
using System.Threading;
using System.Threading.Tasks;
using Microsoft.Data.SqlClient;

public static class StreamVersionRepository
{
    public static async Task<int> GetNextVersionAsync(
        Guid streamId,
        int count,
        int currentVersion,
        string connectionString,
        CancellationToken cancellationToken = default)
    {
        const string sql = @"
            SELECT TOP 1 Version
            FROM StreamVersions
            WHERE StreamId = @streamId
              AND Version > @currentVersion
            ORDER BY Version ASC;";

        await using var connection = new SqlConnection(connectionString);
        await connection.OpenAsync(cancellationToken).ConfigureAwait(false);

        await using var command = new SqlCommand(sql, connection);
        command.Parameters.Add("@streamId", SqlDbType.UniqueIdentifier).Value = streamId;
        command.Parameters.Add("@currentVersion", SqlDbType.Int).Value = currentVersion;

        var result = await command.ExecuteScalarAsync(cancellationToken).ConfigureAwait(false);

        return result is null or DBNull ? -1 : Convert.ToInt32(result);
    }
}
