<?php
/**
 * Retrieve nearby places using Google Places API.
 *
 * @param string $location   Latitude,longitude (e.g., "37.7749,-122.4194")
 * @param string $pageToken  Optional page token for pagination (null for first page)
 * @return string            JSON-encoded list of places or error message
 */
function getNearbyPlaces(string $location, ?string $pageToken = null): string
{
    // Load API key from a secure environment variable
    $apiKey = getenv('GOOGLE_PLACES_API_KEY');
    if (!$apiKey) {
        return json_encode(['error' => 'API key not configured']);
    }

    // Base endpoint for Nearby Search
    $endpoint = 'https://maps.googleapis.com/maps/api/place/nearbysearch/json';

    // Build query parameters
    $params = [
        'key'      => $apiKey,
        'location' => $location,
        'radius'   => 5000,               // radius in meters; adjust as needed
        'type'     => 'point_of_interest' // generic type; customize per use‑case
    ];

    // Include pagination token if provided
    if ($pageToken) {
        $params['pagetoken'] = $pageToken;
    }

    // Construct full URL with encoded query string
    $url = $endpoint . '?' . http_build_query($params);

    // Initialize cURL with secure defaults
    $ch = curl_init();
    curl_setopt_array($ch, [
        CURLOPT_URL            => $url,
        CURLOPT_RETURNTRANSFER => true,
        CURLOPT_TIMEOUT        => 10,
        CURLOPT_SSL_VERIFYPEER => true,
        CURLOPT_SSL_VERIFYHOST => 2,
    ]);

    $response = curl_exec($ch);
    $curlErr   = curl_error($ch);
    curl_close($ch);

    if ($response === false) {
        return json_encode(['error' => 'cURL error: ' . $curlErr]);
    }

    // Decode API response to verify status
    $data = json_decode($response, true);
    if (json_last_error() !== JSON_ERROR_NONE) {
        return json_encode(['error' => 'Invalid JSON from API']);
    }

    // Propagate API errors if any
    if (isset($data['status']) && $data['status'] !== 'OK' && $data['status'] !== 'ZERO_RESULTS') {
        return json_encode(['error' => 'API error: ' . $data['status']]);
    }

    // Return the raw list of places (or empty array) as JSON
    return json_encode([
        'places'    => $data['results'] ?? [],
        'next_page' => $data['next_page_token'] ?? null
    ]);
}
